const works = [{"type":"Lettering Study","title":"Infinite Love","desc":"Layered script, saturated color, and a strong central mark give this piece the feeling of a studio signature. The work keeps the message direct while letting texture and light carry the surface.","src":"data:image/jpeg;base64,","thumb":"data:image/jpeg;base64,","medium":"Lettering Study","collection":"Selected Works","availability":"Portfolio review"},{"type":"Wood / Lettering","title":"Do Not Despair","desc":"A circular wood-based statement piece shaped by grain, pressure, and a hand-finished surface. The wording is direct, but the material gives it a grounded, weathered presence.","src":"data:image/jpeg;base64,","thumb":"data:image/jpeg;base64,","medium":"Wood / Lettering","collection":"Selected Works","availability":"Portfolio review"},{"type":"Pattern Study","title":"Sunflower Mandala","desc":"A radial composition built from blue, gold, and petal-like repetition. The piece sits between ornament, symbol, and decorative surface design.","src":"data:image/jpeg;base64,","thumb":"data:image/jpeg;base64,","medium":"Pattern Study","collection":"Selected Works","availability":"Portfolio review"},{"type":"Texture Study","title":"Blue Field","desc":"A close study of blue surface, grain, and directional movement. It works as a quiet counterpoint to the more message-driven pieces in the collection.","src":"data:image/jpeg;base64,","thumb":"data:image/jpeg;base64,","medium":"Texture Study","collection":"Selected Works","availability":"Portfolio review"},{"type":"Mixed Media","title":"Love, Weathered","desc":"A distressed love study where teal, red, and worn texture meet in a print-like field. The piece feels handled, layered, and intentionally imperfect.","src":"data:image/jpeg;base64,","thumb":"data:image/jpeg;base64,","medium":"Mixed Media","collection":"Selected Works","availability":"Portfolio review"},{"type":"Lettering","title":"You Are Priceless","desc":"A warm lettering piece with a simple affirmation at its center. The script keeps the message personal without turning it into decoration alone.","src":"data:image/jpeg;base64,","thumb":"data:image/jpeg;base64,","medium":"Lettering","collection":"Selected Works","availability":"Portfolio review"},{"type":"Texture Study","title":"Red Current","desc":"A horizontal texture piece built around speed, friction, and a strong red field. Its movement gives the surface a sense of heat and pressure.","src":"data:image/jpeg;base64,","thumb":"data:image/jpeg;base64,","medium":"Texture Study","collection":"Selected Works","availability":"Portfolio review"},{"type":"Ink Study","title":"Rainline Notes","desc":"Vertical marks gather like weather, notation, or a passing rhythm. The piece uses restraint and repetition instead of a fixed image.","src":"data:image/jpeg;base64,","thumb":"data:image/jpeg;base64,","medium":"Ink Study","collection":"Selected Works","availability":"Portfolio review"},{"type":"Lettering Study","title":"Infinite Love, Blue Variation","desc":"A cooler variation on the Infinite Love mark, softened through blue and violet tones. It shows how the same phrase can shift when the atmosphere changes.","src":"data:image/jpeg;base64,","thumb":"data:image/jpeg;base64,","medium":"Lettering Study","collection":"Selected Works","availability":"Portfolio review"},{"type":"Signature Study","title":"Blue Name Current","desc":"A layered blue surface with a quiet name-form embedded inside the field. The signature becomes part of the current rather than sitting on top of it.","src":"data:image/jpeg;base64,","thumb":"data:image/jpeg;base64,","medium":"Signature Study","collection":"Selected Works","availability":"Portfolio review"},{"type":"Lettering","title":"Blessed Water","desc":"A gentle script piece carried by open space and blue wash. The composition leaves room around the words so the lettering can breathe.","src":"data:image/jpeg;base64,","thumb":"data:image/jpeg;base64,","medium":"Lettering","collection":"Selected Works","availability":"Portfolio review"},{"type":"Ink Study","title":"Soul Current","desc":"A restrained blue field where lettering and surface begin to merge. The piece is more about trace and movement than a finished statement.","src":"data:image/jpeg;base64,","thumb":"data:image/jpeg;base64,","medium":"Ink Study","collection":"Selected Works","availability":"Portfolio review"},{"type":"Digital Lettering","title":"Washed Out","desc":"Expressive lettering moves across a bright digital wash. The contrast between the loose mark and the luminous field gives the piece its tension.","src":"data:image/jpeg;base64,","thumb":"data:image/jpeg;base64,","medium":"Digital Lettering","collection":"Selected Works","availability":"Portfolio review"},{"type":"Brand Mark","title":"Inkspirations Studio Mark","desc":"A hand-drawn studio mark in the Inkspirations blue language. It anchors the portfolio as both identity work and personal lettering.","src":"data:image/jpeg;base64,","thumb":"data:image/jpeg;base64,","medium":"Brand Mark","collection":"Selected Works","availability":"Portfolio review"},{"type":"Digital Collage","title":"Lest We Forget","desc":"A compact memorial-style collage built with distressed color, light, and layered imagery. The piece holds its message through compression rather than scale.","src":"data:image/jpeg;base64,","thumb":"data:image/jpeg;base64,","medium":"Digital Collage","collection":"Selected Works","availability":"Portfolio review"},{"type":"Identity Design","title":"Studio Blue Identity Card","desc":"A polished Inkspirations Studios identity card using the house blue as its main field. It presents the studio voice in a clean, client-facing format.","src":"data:image/jpeg;base64,","thumb":"data:image/jpeg;base64,","medium":"Identity Design","collection":"Selected Works","availability":"Portfolio review"},{"type":"Identity Design","title":"Inkspirations Logo Lockup","desc":"A clean logo lockup pairing calligraphic emphasis with a direct studio name. The piece shows the brand system in its simplest public-facing form.","src":"data:image/jpeg;base64,","thumb":"data:image/jpeg;base64,","medium":"Identity Design","collection":"Selected Works","availability":"Portfolio review"},{"type":"Typographic Poster","title":"Say No","desc":"A stark poster study built from scale, contrast, and compression. The direct wording gives the composition its structure.","src":"data:image/jpeg;base64,","thumb":"data:image/jpeg;base64,","medium":"Typographic Poster","collection":"Selected Works","availability":"Portfolio review"},{"type":"Identity Mark","title":"Small Town Teacher","desc":"A compact identity mark with friendly typography and a warm palette. It shows a softer side of the studio system while staying clear and readable.","src":"data:image/jpeg;base64,","thumb":"data:image/jpeg;base64,","medium":"Identity Mark","collection":"Selected Works","availability":"Portfolio review"}];

let current = 0;

const viewerImg = document.getElementById("viewerImg");
const viewerType = document.getElementById("viewerType");
const viewerTitle = document.getElementById("viewerTitle");
const viewerDesc = document.getElementById("viewerDesc");
const rail = document.getElementById("rail");
const modal = document.getElementById("modal");
const modalImg = document.getElementById("modalImg");
const modalTitle = document.getElementById("modalTitle");

function render(index) {
  current = (index + works.length) % works.length;
  const work = works[current];

  viewerImg.src = work.src;
  viewerImg.alt = work.title;
  viewerType.textContent = work.type || "Artwork";
  viewerTitle.textContent = work.title;
  viewerDesc.textContent = work.desc || "Selected Inkspirations Studios artwork.";

  [...rail.children].forEach((button, buttonIndex) => {
    button.setAttribute("aria-current", String(buttonIndex === current));
  });
}

function openCurrentWork() {
  const work = works[current];
  modalImg.src = work.src;
  modalImg.alt = work.title;
  modalTitle.textContent = work.title;
  modal.classList.add("open");
}

function closeModal() {
  modal.classList.remove("open");
}

works.forEach((work, index) => {
  const button = document.createElement("button");
  button.className = "thumb";
  button.type = "button";
  button.innerHTML = '<img alt="" src="' + work.src + '"><span><span class="thumb-title">' + work.title + '</span><small>' + (work.type || "Artwork") + '</small></span>';
  button.addEventListener("click", () => render(index));
  rail.appendChild(button);
});

document.getElementById("prevWork").addEventListener("click", () => render(current - 1));
document.getElementById("nextWork").addEventListener("click", () => render(current + 1));
document.getElementById("expandWork").addEventListener("click", openCurrentWork);
document.getElementById("closeModal").addEventListener("click", closeModal);

modal.addEventListener("click", (event) => {
  if (event.target === modal) closeModal();
});

window.addEventListener("keydown", (event) => {
  if (event.key === "Escape") closeModal();
  if (event.key === "ArrowRight") render(current + 1);
  if (event.key === "ArrowLeft") render(current - 1);
});

render(0);
